    badge: <path d="M20 4H4c-1.1 0-2 .9-2 2v12c0 1.1.9 2 2 2h16c1.1 0 2-.9 2-2V6c0-1.1-.9-2-2-2zm-8 2.75c1.24 0 2.25 1.01 2.25 2.25s-1.01 2.25-2.25 2.25S9.75 10.24 9.75 9 10.76 6.75 12 6.75zM17 17H7v-1.5c0-1.67 3.33-2.5 5-2.5s5 .83 5 2.5V17z"/>,
    group: <path d="M16 11c1.66 0 2.99-1.34 2.99-3S17.66 5 16 5c-1.66 0-3 1.34-3 3s1.34 3 3 3zm-8 0c1.66 0 2.99-1.34 2.99-3S9.66 5 8 5C6.34 5 5 6.34 5 8s1.34 3 3 3zm0 2c-2.33 0-7 1.17-7 3.5V19h14v-2.5c0-2.33-4.67-3.5-7-3.5zm8 0c-.29 0-.62.02-.97.05 1.16.84 1.97 1.97 1.97 3.45V19h6v-2.5c0-2.33-4.67-3.5-7-3.5z"/>,
    payments: <path d="M11.8 10.9c-2.27-.59-3-1.2-3-2.15 0-1.09 1.01-1.85 2.7-1.85 1.78 0 2.44.85 2.5 2.1h2.21c-.07-1.72-1.12-3.3-3.21-3.81V3h-3v2.16c-1.94.42-3.5 1.68-3.5 3.61 0 2.31 1.91 3.46 4.7 4.13 2.5.6 3 1.48 3 2.41 0 .69-.49 1.79-2.7 1.79-2.06 0-2.87-.92-2.98-2.1h-2.2c.12 2.19 1.76 3.42 3.68 3.83V21h3v-2.15c1.95-.37 3.5-1.5 3.5-3.55 0-2.84-2.43-3.81-4.7-4.4z"/>,
    stock: <path d="M3.5 18.49l6-6.01 4 4L22 6.92l-1.41-1.41-7.09 7.97-4-4L2 16.99z"/>,
    savings: <path d="M19 8H5c-1.66 0-3 1.34-3 3v6h4v4h12v-4h4v-6c0-1.66-1.34-3-3-3zm-3 11H8v-5h8v5zm3-7c-.55 0-1-.45-1-1s.45-1 1-1 1 .45 1 1-.45 1-1 1zm-1-9H6v4h12V3z"/>,
  };
  return <svg viewBox="0 0 24 24" fill="currentColor">{icons[name]}</svg>;
}

function Dashboard() {
  const [stats, setStats] = useState(null);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const { data } = await api.get('/dashboard/stats');
        setStats(data.data);
      } catch (error) {
        console.error('Error fetching stats:', error);
      }
    };
    fetchStats();
  }, []);

  const statCards = stats ? [
    { label: 'Total Members', value: stats.totalMembers, icon: 'group', color: '#667eea' },
    { label: 'Active Members', value: stats.activeMembers, icon: 'check', color: '#48bb78' },
    { label: 'Loan Members', value: stats.loanMembers, icon: 'payments', color: '#ed8936' },
    { label: 'Share Members', value: stats.shareMembers, icon: 'stock', color: '#9f7aea' },
    { label: 'Savings Members', value: stats.savingsMembers, icon: 'savings', color: '#38b2ac' },
    { label: 'Total Loans', value: `Rs. ${(stats.totalLoanAmount || 0).toLocaleString()}`, icon: 'money', color: '#f56565' },
    { label: 'Total Savings', value: `Rs. ${(stats.totalSavings || 0).toLocaleString()}`, icon: 'bank', color: '#4299e1' },
    { label: 'Total Shares', value: `Rs. ${(stats.totalShares || 0).toLocaleString()}`, icon: 'chart', color: '#667eea' },
  ] : [];

  return (
    <div className="dashboard">
      <header className="page-header">
        <h1>Sanaduk Saving and Credit Cooperative Ltd.</h1>
        <p>Welcome back, {localStorage.getItem('user') ? JSON.parse(localStorage.getItem('user')).username : 'User'}</p>
      </header>
      
      {/* Cooperative Introduction */}
      <div className="cooperative-intro">
        <h2>About Our Cooperative</h2>
        <p>
          Sanaduk Saving and Credit Cooperative Ltd. is dedicated to providing financial services 
          and support to our members. We offer loans, savings accounts, and share programs to help 
          individuals and businesses grow and thrive together.
        </p>
        <p>
          Our mission is to promote savings culture, provide affordable credit, and contribute to 
          the economic development of our community.
        </p>
      </div>

      <h2 className="section-title">Dashboard Overview</h2>
      <div className="stats-grid">
        {statCards.map((stat, index) => (
          <div key={index} className="stat-card">
            <div className="stat-icon" style={{ backgroundColor: `${stat.color}20`, color: stat.color }}>
              <NavIcon name={stat.icon} />
            </div>
            <div className="stat-content">
              <span className="stat-value">{stat.value}</span>
              <span className="stat-label">{stat.label}</span>
            </div>
