        ))}
      </div>
      <div className="dashboard-cards">
        <div className="dashboard-card">
          <h3>Quick Actions</h3>
          <div className="quick-actions">
            <Link to="/citizenship" className="action-btn">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M12 5v14M5 12h14"/>
              </svg>
              Add Citizenship
            </Link>
            <Link to="/members" className="action-btn">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M12 5v14M5 12h14"/>
              </svg>
              New Member
            </Link>
            <Link to="/loans" className="action-btn">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M12 5v14M5 12h14"/>
              </svg>
              New Loan
            </Link>
            <Link to="/shares" className="action-btn">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M12 5v14M5 12h14"/>
              </svg>
              Buy Shares
            </Link>
            <Link to="/savings" className="action-btn">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                <path d="M12 5v14M5 12h14"/>
              </svg>
              Open Savings
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
}

function CitizenshipPage() {
  const [records, setRecords] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editData, setEditData] = useState(null);
  const [viewData, setViewData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    fetchRecords();
  }, []);

  const fetchRecords = async () => {
    try {
      const { data } = await api.get('/citizenship');
      setRecords(data.data);
    } catch (error) {
      console.error('Error fetching citizenship records:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    const formData = new FormData(e.target);
    
    try {
      if (editData) {
        await api.put(`/citizenship/${editData.id}`, formData);
      } else {
        await api.post('/citizenship', formData);
      }
      fetchRecords();
      setShowModal(false);
      setEditData(null);
      e.target.reset();
    } catch (error) {
      alert(error.response?.data?.error || 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (record) => {
    setEditData(record);
    setShowModal(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this record?')) {
      try {
        await api.delete(`/citizenship/${id}`);
        fetchRecords();
      } catch (error) {
        alert(error.response?.data?.error || 'An error occurred');
      }
    }
  };

  const handleView = (record) => {
    setViewData(record);
  };

  const filteredRecords = records.filter(r => 
    r.full_name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    r.citizenship_number?.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="page">
      <header className="page-header">
        <h1>Citizenship Management</h1>
        <button className="btn-primary" onClick={() => { setEditData(null); setShowModal(true); }}>
          + Add Citizenship
        </button>
      </header>
      <div className="table-container">
        <div className="table-header">
          <input
            type="text"
            placeholder="Search by name or citizenship number..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="search-input"
          />
        </div>
        <table className="data-table">
          <thead>
            <tr>
              <th>Citizenship No.</th>
              <th>Full Name</th>
              <th>Gender</th>
              <th>Date of Birth (B.S)</th>
              <th>Phone</th>
              <th>District</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredRecords.map((record) => (
              <tr key={record.id}>
                <td>{record.citizenship_number}</td>
                <td>{record.full_name}</td>
                <td>{record.gender}</td>
                <td>{record.birth_date_bs || record.birth_date}</td>
                <td>{record.phone}</td>
                <td>{record.issued_district}</td>
                <td>
                  <div className="action-buttons">
                    <button className="btn-icon view" onClick={() => handleView(record)}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/>
                        <circle cx="12" cy="12" r="3"/>
                      </svg>
                    </button>
                    <button className="btn-icon edit" onClick={() => handleEdit(record)}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/>
                      </svg>
                    </button>
                    <button className="btn-icon delete" onClick={() => handleDelete(record.id)}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <path d="M3 6h18M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/>
                      </svg>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{editData ? 'Edit Citizenship' : 'Add Citizenship'}</h2>
              <button className="modal-close" onClick={() => setShowModal(false)}>&times;</button>
            </div>
            <form onSubmit={handleSubmit} encType="multipart/form-data" className="modal-form">
              <div className="form-section">
                <h3>Basic Information</h3>
                <div className="form-row">
                  <div className="form-group">
                    <label>Citizenship Number *</label>
                    <input name="citizenship_number" defaultValue={editData?.citizenship_number} required />
                  </div>
                  <div className="form-group">
                    <label>Full Name *</label>
                    <input name="full_name" defaultValue={editData?.full_name} required />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Gender</label>
                    <select name="gender" defaultValue={editData?.gender}>
                      <option value="">Select</option>
                      <option value="Male">Male</option>
                      <option value="Female">Female</option>
                      <option value="Other">Other</option>
                    </select>
                  </div>
                  <div className="form-group">
                    <label>Birth Date (A.D)</label>
                    <input type="date" name="birth_date" defaultValue={editData?.birth_date} />
                  </div>
                  <div className="form-group">
                    <label>Birth Date (B.S)</label>
                    <input type="text" name="birth_date_bs" defaultValue={editData?.birth_date_bs} placeholder="YYYY/MM/DD (B.S)" />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Birth Place</label>
                    <input name="birth_place" defaultValue={editData?.birth_place} />
                  </div>
                  <div className="form-group">
                    <label>Nationality</label>
                    <input name="nationality" defaultValue={editData?.nationality || 'Nepali'} />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Religion</label>
                    <input name="religion" defaultValue={editData?.religion} />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Marital Status</label>
                    <select name="marital_status" defaultValue={editData?.marital_status || ''}>
                      <option value="">Select</option>
                      <option value="Single">Single</option>
                      <option value="Married">Married</option>
                      <option value="Divorced">Divorced</option>
                      <option value="Widowed">Widowed</option>
                    </select>
                  </div>
                </div>
              </div>
              <div className="form-section">
                <h3>Photo & Documents</h3>
                <div className="form-row">
                  <div className="form-group">
                    <label>Profile Photo</label>
                    <input type="file" name="photo" accept="image/*" />
                    {editData?.photo && <p className="file-hint">Current: {editData.photo}</p>}
                    <input type="hidden" name="existing_photo" value={editData?.photo || ''} />
                  </div>
                  <div className="form-group">
                    <label>Citizenship Front</label>
                    <input type="file" name="citizenship_front" accept="image/*" />
                    {editData?.citizenship_front && <p className="file-hint">Current: {editData.citizenship_front}</p>}
                    <input type="hidden" name="existing_citizenship_front" value={editData?.citizenship_front || ''} />
                  </div>
                  <div className="form-group">
                    <label>Citizenship Back</label>
                    <input type="file" name="citizenship_back" accept="image/*" />
                    {editData?.citizenship_back && <p className="file-hint">Current: {editData.citizenship_back}</p>}
                    <input type="hidden" name="existing_citizenship_back" value={editData?.citizenship_back || ''} />
                  </div>
                </div>
              </div>
              <div className="form-section">
                <h3>Issuing Details</h3>
                <div className="form-row">
                  <div className="form-group">
                    <label>Issued District *</label>
                    <input name="issued_district" defaultValue={editData?.issued_district} required />
                  </div>
                  <div className="form-group">
                    <label>Issued Date</label>
                    <input type="date" name="issued_date" defaultValue={editData?.issued_date} />
                  </div>
                </div>
              </div>
              <div className="form-section">
                <h3>Address</h3>
                <div className="form-row">
                  <div className="form-group">
                    <label>Province Name</label>
                    <select name="province" defaultValue={editData?.province}>
                      <option value="">Select Province</option>
                      <option value="Province 1">Koshi province</option>
                      <option value="Province 2">Madhesh Province</option>
                      <option value="Province 3">Bagmati Province</option>
                      <option value="Province 4">Gandaki Province</option>
                      <option value="Province 5">Lumbini Province</option>
                      <option value="Province 6">Karnali Province</option>
                      <option value="Province 7">Sudurpaschim Province</option>
                    </select>
                  </div>
                  <div className="form-group">
                    <label>District</label>
                    <input name="district" defaultValue={editData?.district} />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Municipality</label>
                    <input name="municipality" defaultValue={editData?.municipality} />
                  </div>
                  <div className="form-group">
                    <label>Ward Number</label>
                    <input name="ward_number" defaultValue={editData?.ward_number} />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Tole</label>
                    <input name="tole" defaultValue={editData?.tole} />
                  </div>
                </div>
              </div>
              <div className="form-section">
                <h3>Contact Info</h3>
                <div className="form-row">
                  <div className="form-group">
