function MembersPage() {
  const [members, setMembers] = useState([]);
  const [citizenshipList, setCitizenshipList] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editData, setEditData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState('');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [membersRes, citizenshipRes] = await Promise.all([
        api.get('/members'),
        api.get('/citizenship')
      ]);
      setMembers(membersRes.data.data);
      setCitizenshipList(citizenshipRes.data.data);
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    const formData = new FormData(e.target);
    const submitData = Object.fromEntries(formData.entries());
    
    try {
      if (editData) {
        await api.put(`/members/${editData.id}`, submitData);
      } else {
        await api.post('/members', submitData);
      }
      fetchData();
      setShowModal(false);
      setEditData(null);
      e.target.reset();
    } catch (error) {
      alert(error.response?.data?.error || 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (member) => {
    setEditData(member);
    setShowModal(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this member?')) {
      try {
        await api.delete(`/members/${id}`);
        fetchData();
      } catch (error) {
        alert(error.response?.data?.error || 'An error occurred');
      }
    }
  };

  const filteredMembers = members.filter(m => {
    const matchesSearch = 
      m.member_number?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      m.member_name?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = !typeFilter || m.membership_type === typeFilter;
    return matchesSearch && matchesType;
  });

  return (
    <div className="page">
      <header className="page-header">
        <h1>Members Management</h1>
        <button className="btn-primary" onClick={() => { setEditData(null); setShowModal(true); }}>
          + Add Member
        </button>
      </header>
      <div className="filter-bar">
        <input
          type="text"
          placeholder="Search by member number or name..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="search-input"
        />
        <select value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)} className="filter-select">
          <option value="">All Types</option>
          <option value="loan">Loan</option>
          <option value="share">Share</option>
          <option value="savings">Savings</option>
        </select>
      </div>
      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr>
              <th>Member No.</th>
              <th>Name</th>
              <th>Type</th>
              <th>Phone</th>
              <th>Email</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredMembers.map((member) => (
              <tr key={member.id}>
                <td>{member.member_number}</td>
                <td>{member.member_name || 'N/A'}</td>
                <td>
                  <span className={`badge badge-${member.membership_type}`}>
                    {member.membership_type}
                  </span>
                </td>
                <td>{member.phone}</td>
                <td>{member.email}</td>
                <td>
                  <span className={`status-badge ${member.status}`}>
                    {member.status}
                  </span>
                </td>
                <td>
                  <div className="action-buttons">
                    <button className="btn-icon edit" onClick={() => handleEdit(member)}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/>
                      </svg>
                    </button>
                    <button className="btn-icon delete" onClick={() => handleDelete(member.id)}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <path d="M3 6h18M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/>
                      </svg>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{editData ? 'Edit Member' : 'Add New Member'}</h2>
              <button className="modal-close" onClick={() => setShowModal(false)}>&times;</button>
            </div>
            <form onSubmit={handleSubmit} className="modal-form">
              <div className="form-row">
                <div className="form-group">
                  <label>Citizenship Record *</label>
                  <select name="citizenship_id" defaultValue={editData?.citizenship_id || ''} required>
                    <option value="">Select Citizenship</option>
                    {citizenshipList.map((c) => (
                      <option key={c.id} value={c.id}>
                        {c.full_name} - {c.citizenship_number}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="form-group">
                  <label>Membership Type *</label>
                  <select name="membership_type" defaultValue={editData?.membership_type} required>
                    <option value="loan">Loan Member</option>
                    <option value="share">Share Member</option>
                    <option value="savings">Savings Member</option>
                  </select>
                </div>
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label>Membership Date</label>
                  <input type="date" name="membership_date" defaultValue={editData?.membership_date} />
                </div>
                <div className="form-group">
                  <label>Status</label>
                  <select name="status" defaultValue={editData?.status || 'active'}>
                    <option value="active">Active</option>
                    <option value="inactive">Inactive</option>
                    <option value="suspended">Suspended</option>
                  </select>
                </div>
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label>Phone</label>
                  <input name="phone" defaultValue={editData?.phone} />
                </div>
                <div className="form-group">
                  <label>Email</label>
                  <input type="email" name="email" defaultValue={editData?.email} />
                </div>
              </div>
              <div className="modal-actions">
                <button type="button" className="btn-secondary" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn-primary" disabled={loading}>
                  {loading ? 'Saving...' : (editData ? 'Update' : 'Save')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

