              <th>Total Shares</th>
              <th>Share Value</th>
              <th>Total Amount</th>
              <th>Purchase Date</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredShares.map((share) => (
              <tr key={share.id}>
                <td>{share.share_number}</td>
                <td>{share.member_name}</td>
                <td>{share.total_shares}</td>
                <td>Rs. {share.share_value}</td>
                <td>Rs. {share.total_amount?.toLocaleString()}</td>
                <td>{share.purchase_date}</td>
                <td>
                  <span className={`status-badge ${share.status}`}>{share.status}</span>
                </td>
                <td>
                  <div className="action-buttons">
                    <button className="btn-icon edit" onClick={() => handleEdit(share)}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/>
                      </svg>
                    </button>
                    <button className="btn-icon delete" onClick={() => handleDelete(share.id)}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <path d="M3 6h18M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/>
                      </svg>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{editData ? 'Edit Shares' : 'Buy Shares'}</h2>
              <button className="modal-close" onClick={() => setShowModal(false)}>&times;</button>
            </div>
            <form onSubmit={handleSubmit} className="modal-form">
              <div className="form-row">
                <div className="form-group">
                  <label>Member *</label>
                  <select name="member_id" defaultValue={editData?.member_id} required>
                    <option value="">Select Member</option>
                    {members.filter(m => m.status === 'active').map((m) => (
                      <option key={m.id} value={m.id}>
                        {m.member_name} - {m.member_number}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="form-group">
                  <label>Total Shares *</label>
                  <input type="number" name="total_shares" defaultValue={editData?.total_shares || 10} required />
                </div>
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label>Share Value (Rs.)</label>
                  <input type="number" name="share_value" step="0.01" defaultValue={editData?.share_value || 100} />
                </div>
                <div className="form-group">
                  <label>Purchase Date</label>
                  <input type="date" name="purchase_date" defaultValue={editData?.purchase_date} />
                </div>
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label>Dividend Rate (%)</label>
                  <input type="number" name="dividend_rate" step="0.01" defaultValue={editData?.dividend_rate} />
                </div>
                <div className="form-group">
                  <label>Status</label>
                  <select name="status" defaultValue={editData?.status || 'active'}>
                    <option value="active">Active</option>
                    <option value="inactive">Inactive</option>
                    <option value="transferred">Transferred</option>
                  </select>
                </div>
              </div>
              <div className="modal-actions">
                <button type="button" className="btn-secondary" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn-primary" disabled={loading}>
                  {loading ? 'Saving...' : (editData ? 'Update' : 'Purchase')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

function SavingsPage() {
  const [savings, setSavings] = useState([]);
  const [members, setMembers] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [editData, setEditData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [typeFilter, setTypeFilter] = useState('');

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [savingsRes, membersRes] = await Promise.all([
        api.get('/savings'),
        api.get('/members')
      ]);
      setSavings(savingsRes.data.data);
      setMembers(membersRes.data.data);
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    const formData = new FormData(e.target);
    const submitData = Object.fromEntries(formData.entries());
    
    try {
      if (editData) {
        await api.put(`/savings/${editData.id}`, submitData);
      } else {
        await api.post('/savings', submitData);
      }
      fetchData();
      setShowModal(false);
      setEditData(null);
      e.target.reset();
    } catch (error) {
      alert(error.response?.data?.error || 'An error occurred');
    } finally {
      setLoading(false);
    }
  };

  const handleEdit = (saving) => {
    setEditData(saving);
    setShowModal(true);
  };

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this savings account?')) {
      try {
        await api.delete(`/savings/${id}`);
        fetchData();
      } catch (error) {
        alert(error.response?.data?.error || 'An error occurred');
      }
    }
  };

  const filteredSavings = savings.filter(s => {
    const matchesSearch = 
      s.account_number?.toLowerCase().includes(searchTerm.toLowerCase()) ||
      s.member_name?.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesType = !typeFilter || s.account_type === typeFilter;
    return matchesSearch && matchesType;
  });

  return (
    <div className="page">
      <header className="page-header">
        <h1>Savings Management</h1>
        <button className="btn-primary" onClick={() => { setEditData(null); setShowModal(true); }}>
          + Open Savings
        </button>
      </header>
      <div className="filter-bar">
        <input
          type="text"
          placeholder="Search by account number or member name..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="search-input"
        />
        <select value={typeFilter} onChange={(e) => setTypeFilter(e.target.value)} className="filter-select">
          <option value="">All Types</option>
          <option value="regular">Regular Savings</option>
          <option value="fixed">Fixed Deposit</option>
          <option value="recurring">Recurring Deposit</option>
          <option value="current">Current Account</option>
        </select>
      </div>
      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr>
              <th>Account No.</th>
              <th>Member</th>
              <th>Type</th>
              <th>Balance</th>
              <th>Interest Rate</th>
              <th>Opening Date</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {filteredSavings.map((saving) => (
              <tr key={saving.id}>
                <td>{saving.account_number}</td>
                <td>{saving.member_name}</td>
                <td>
                  <span className={`badge badge-${saving.account_type}`}>
                    {saving.account_type}
                  </span>
                </td>
                <td>Rs. {saving.current_balance?.toLocaleString()}</td>
                <td>{saving.interest_rate}%</td>
                <td>{saving.opening_date}</td>
                <td>
                  <span className={`status-badge ${saving.status}`}>{saving.status}</span>
                </td>
                <td>
                  <div className="action-buttons">
                    <button className="btn-icon edit" onClick={() => handleEdit(saving)}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/>
                      </svg>
                    </button>
                    <button className="btn-icon delete" onClick={() => handleDelete(saving.id)}>
                      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <path d="M3 6h18M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/>
                      </svg>
                    </button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>{editData ? 'Edit Savings' : 'Open Savings Account'}</h2>
              <button className="modal-close" onClick={() => setShowModal(false)}>&times;</button>
            </div>
            <form onSubmit={handleSubmit} className="modal-form">
              <div className="form-row">
                <div className="form-group">
                  <label>Member *</label>
                  <select name="member_id" defaultValue={editData?.member_id} required>
                    <option value="">Select Member</option>
                    {members.filter(m => m.status === 'active').map((m) => (
                      <option key={m.id} value={m.id}>
                        {m.member_name} - {m.member_number}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="form-group">
                  <label>Account Type *</label>
                  <select name="account_type" defaultValue={editData?.account_type} required>
                    <option value="regular">Regular Savings</option>
                    <option value="fixed">Fixed Deposit</option>
                    <option value="recurring">Recurring Deposit</option>
                    <option value="current">Current Account</option>
                  </select>
                </div>
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label>Opening Date</label>
                  <input type="date" name="opening_date" defaultValue={editData?.opening_date} />
                </div>
                <div className="form-group">
                  <label>Interest Rate (%)</label>
                  <input type="number" name="interest_rate" step="0.01" defaultValue={editData?.interest_rate || 5} />
                </div>
              </div>
              <div className="form-row">
                <div className="form-group">
                  <label>Status</label>
                  <select name="status" defaultValue={editData?.status || 'active'}>
                    <option value="active">Active</option>
                    <option value="inactive">Inactive</option>
                    <option value="closed">Closed</option>
                    <option value="frozen">Frozen</option>
                  </select>
                </div>
              </div>
              <div className="modal-actions">
                <button type="button" className="btn-secondary" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn-primary" disabled={loading}>
                  {loading ? 'Saving...' : (editData ? 'Update' : 'Open Account')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

function MonthlySavingsPage() {
  const [members, setMembers] = useState([]);
  const [selectedMember, setSelectedMember] = useState('');
  const [selectedYear, setSelectedYear] = useState(2082); // Nepali year
  const [monthlyData, setMonthlyData] = useState({});
  const [summary, setSummary] = useState(null);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);

  const months = [
    { value: 1, name: 'Baisakh' },
    { value: 2, name: 'Jestha' },
    { value: 3, name: 'Ashadh' },
    { value: 4, name: 'Shrawan' },
    { value: 5, name: 'Bhadra' },
    { value: 6, name: 'Ashwin' },
    { value: 7, name: 'Kartik' },
    { value: 8, name: 'Mangsir' },
    { value: 9, name: 'Poush' },
    { value: 10, name: 'Magh' },
    { value: 11, name: 'Falgun' },
    { value: 12, name: 'Chaitra' }
  ];

  const nepaliMonths = [
    'Baisakh', 'Jestha', 'Ashadh', 'Shrawan', 'Bhadra', 'Ashwin',
    'Kartik', 'Mangsir', 'Poush', 'Magh', 'Falgun', 'Chaitra'
  ];

  // Nepali years (Bikram Sambat) - current year is around 2082
  const years = Array.from({ length: 16 }, (_, i) => 2075 + i);

  useEffect(() => {
    fetchMembers();
  }, []);

  useEffect(() => {
    if (selectedMember && selectedYear) {
      fetchMonthlyData();
      fetchSummary();
    }
  }, [selectedMember, selectedYear]);

  const fetchMembers = async () => {
    try {
      const { data } = await api.get('/members');
      setMembers(data.data || []);
    } catch (error) {
      console.error('Error fetching members:', error);
    }
  };

  const fetchMonthlyData = async () => {
    setLoading(true);
    try {
      const { data } = await api.get(`/monthly-savings?member_id=${selectedMember}&year=${selectedYear}`);
      const monthlyMap = {};
      (data.data || []).forEach(item => {
        monthlyMap[item.month] = item;
      });
      setMonthlyData(monthlyMap);
    } catch (error) {
      console.error('Error fetching monthly data:', error);
    }
    setLoading(false);
  };

  const fetchSummary = async () => {
    try {
      const url = selectedMember 
        ? `/monthly-savings/summary?year=${selectedYear}`
        : `/monthly-savings/summary?year=${selectedYear}`;
      const { data } = await api.get(url);
      setSummary(data.data);
    } catch (error) {
      console.error('Error fetching summary:', error);
    }
  };

  const handleSaveMonth = async (month) => {
    const amount = monthlyData[month]?.total_amount || 0;
    setSaving(true);
    try {
      await api.post('/monthly-savings', {
        member_id: selectedMember,
        year: selectedYear,
        month: month,
        month_name: nepaliMonths[month - 1],
        total_amount: amount
      });
      fetchMonthlyData();
      fetchSummary();
      alert('Monthly savings saved successfully!');
    } catch (error) {
      console.error('Error saving monthly savings:', error);
      alert('Error saving monthly savings');
    }
    setSaving(false);
  };

  const handleDeleteMonth = async (month) => {
    const entry = monthlyData[month];
    if (!entry?.id) return;
    
    if (!confirm('Are you sure you want to delete this entry?')) return;
    
    try {
      await api.delete(`/monthly-savings/${entry.id}`);
      fetchMonthlyData();
      fetchSummary();
    } catch (error) {
      console.error('Error deleting entry:', error);
      alert('Error deleting entry');
    }
  };

  const getYearlyTotal = () => {
    return Object.values(monthlyData).reduce((sum, item) => sum + (item.total_amount || 0), 0);
  };

  return (
    <div className="monthly-savings-page">
      <header className="page-header">
        <h1>Monthly Savings Management (B.S.)</h1>
        <p>Manage monthly savings for each member</p>
      </header>

      <div className="filter-bar">
        <select 
          value={selectedMember} 
          onChange={(e) => setSelectedMember(e.target.value)}
          className="filter-select"
        >
          <option value="">Select Member</option>
          {members.map(member => (
            <option key={member.id} value={member.id}>
              {member.member_number} - {member.member_name}
            </option>
          ))}
        </select>
        
        <select 
          value={selectedYear} 
          onChange={(e) => setSelectedYear(parseInt(e.target.value))}
          className="filter-select"
        >
          {years.map(year => (
            <option key={year} value={year}>{year}</option>
          ))}
        </select>
      </div>

      {selectedMember && (
        <>
          {/* Yearly Summary */}
          {summary && (
            <div className="summary-cards">
              <div className="summary-card">
                <h3>Yearly Total Savings</h3>
                <span className="summary-value">Rs. {(summary.grandTotal || 0).toLocaleString()}</span>
              </div>
              <div className="summary-card">
                <h3>Total This Year</h3>
                <span className="summary-value">Rs. {getYearlyTotal().toLocaleString()}</span>
              </div>
              <div className="summary-card">
                <h3>Months Recorded</h3>
                <span className="summary-value">{Object.keys(monthlyData).length}/12</span>
              </div>
            </div>
          )}

          {/* Monthly Input Grid */}
          <div className="monthly-grid">
            <h3>Monthly Savings for {selectedYear}</h3>
            <div className="months-container">
              {months.map((month, index) => (
                <div key={month.value} className="month-card">
                  <div className="month-header">
                    <span className="month-name">{month.name}</span>
                    <span className="month-number">{month.value}</span>
                  </div>
                  <div className="month-input">
                    <label>Amount (Rs.)</label>
                    <input
                      type="number"
                      value={monthlyData[month.value]?.total_amount || ''}
                      onChange={(e) => setMonthlyData(prev => ({
                        ...prev,
                        [month.value]: {
                          ...prev[month.value],
                          total_amount: parseFloat(e.target.value) || 0
                        }
                      }))}
                      placeholder="0"
                    />
                  </div>
                  <div className="month-actions">
                    <button 
                      className="btn-primary btn-sm"
                      onClick={() => handleSaveMonth(month.value)}
                      disabled={saving}
                    >
                      Save
                    </button>
                    {monthlyData[month.value]?.id && (
                      <button 
                        className="btn-danger btn-sm"
                        onClick={() => handleDeleteMonth(month.value)}
                      >
                        Delete
                      </button>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Yearly Overview */}
          <div className="yearly-overview">
            <h3>Yearly Overview</h3>
            <div className="yearly-chart">
              {months.map((month, index) => {
                const amount = monthlyData[month.value]?.total_amount || 0;
                const maxAmount = Math.max(...Object.values(monthlyData).map(m => m.total_amount || 0), 1);
                const height = maxAmount > 0 ? (amount / maxAmount) * 100 : 0;
                
                return (
                  <div key={month.value} className="chart-bar-container">
                    <div className="chart-bar" style={{ height: `${height}%` }}></div>
                    <span className="chart-label">{month.name.substring(0, 3)}</span>
                    <span className="chart-value">Rs. {amount.toLocaleString()}</span>
                  </div>
                );
              })}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

function ProfilePage() {
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [activeTab, setActiveTab] = useState('profile');
  const { updateUser } = useAuth();
  
  useEffect(() => {
    fetchProfile();
  }, []);
  
  const fetchProfile = async () => {
    try {
      const { data } = await api.get('/profile');
      setProfile(data.user);
    } catch (error) {
      console.error('Error fetching profile:', error);
    } finally {
      setLoading(false);
    }
  };
  
  const handleProfileUpdate = async (e) => {
    e.preventDefault();
    setSaving(true);
    const formData = new FormData(e.target);
    
    try {
      await api.put('/profile', formData);
      alert('Profile updated successfully!');
      // Force refresh to update sidebar
      window.location.reload();
    } catch (error) {
      alert(error.response?.data?.error || 'An error occurred');
    } finally {
      setSaving(false);
    }
  };
  
  const handlePasswordChange = async (e) => {
    e.preventDefault();
    setSaving(true);
    const formData = new FormData(e.target);
    const data = Object.fromEntries(formData.entries());
    
    if (data.newPassword !== data.confirmPassword) {
      alert('New passwords do not match!');
      setSaving(false);
      return;
    }
    
    try {
      await api.put('/profile/password', data);
      alert('Password changed successfully!');
      e.target.reset();
    } catch (error) {
      alert(error.response?.data?.error || 'An error occurred');
    } finally {
      setSaving(false);
    }
  };
  
  if (loading) {
    return (
      <div className="loading-screen">
        <div className="spinner-large"></div>
        <p>Loading profile...</p>
      </div>
    );
  }
  
  return (
    <div className="profile-page">
      <header className="page-header">
        <h1>My Profile</h1>
      </header>
      
      <div className="profile-container">
        <div className="profile-sidebar">
          <div className="profile-avatar">
            {profile?.profile_photo ? (
              <img src={`http://localhost:3001${profile.profile_photo}`} alt="Profile" />
            ) : (
              <div className="avatar-placeholder">
                {profile?.username?.charAt(0).toUpperCase()}
              </div>
            )}
          </div>
          <h3>{profile?.full_name || profile?.username}</h3>
          <p className="profile-role">{profile?.role}</p>
        </div>
        
        <div className="profile-content">
          <div className="profile-tabs">
            <button 
              className={`tab ${activeTab === 'profile' ? 'active' : ''}`}
              onClick={() => setActiveTab('profile')}
            >
              Edit Profile
            </button>
            <button 
              className={`tab ${activeTab === 'password' ? 'active' : ''}`}
              onClick={() => setActiveTab('password')}
            >
              Change Password
            </button>
          </div>
          
          {activeTab === 'profile' && (
            <div className="tab-content">
              <h2>Profile Information</h2>
              <form onSubmit={handleProfileUpdate} encType="multipart/form-data" className="profile-form">
                <div className="form-section">
                  <h3>Personal Information</h3>
                  <div className="form-row">
                    <div className="form-group">
                      <label>Full Name</label>
                      <input name="full_name" defaultValue={profile?.full_name || ''} placeholder="Enter your full name" />
                    </div>
                    <div className="form-group">
                      <label>Username</label>
                      <input value={profile?.username || ''} disabled />
                    </div>
                  </div>
                  <div className="form-row">
                    <div className="form-group">
                      <label>Email</label>
                      <input type="email" value={profile?.email || ''} disabled />
                    </div>
                  </div>
                  <div className="form-row">
                    <div className="form-group">
                      <label>Profile Photo</label>
                      <input type="file" name="profile_photo" accept="image/*" />
                      {profile?.profile_photo && <p className="file-hint">Current: {profile.profile_photo}</p>}
                      <input type="hidden" name="existing_photo" value={profile?.profile_photo || ''} />
                    </div>
                  </div>
                </div>
                <div className="modal-actions">
                  <button type="submit" className="btn-primary" disabled={saving}>
                    {saving ? 'Saving...' : 'Save Changes'}
                  </button>
                </div>
              </form>
            </div>
          )}
          
          {activeTab === 'password' && (
            <div className="tab-content">
              <h2>Change Password</h2>
              <form onSubmit={handlePasswordChange} className="password-form">
                <div className="form-section">
                  <h3>Security</h3>
                  <div className="form-row">
                    <div className="form-group">
                      <label>Current Password</label>
                      <input type="password" name="currentPassword" required />
                    </div>
                  </div>
                  <div className="form-row">
                    <div className="form-group">
                      <label>New Password</label>
                      <input type="password" name="newPassword" required minLength="6" />
                    </div>
                  </div>
                  <div className="form-row">
                    <div className="form-group">
                      <label>Confirm New Password</label>
                      <input type="password" name="confirmPassword" required />
                    </div>
                  </div>
                </div>
                <div className="modal-actions">
                  <button type="submit" className="btn-primary" disabled={saving}>
                    {saving ? 'Changing...' : 'Change Password'}
                  </button>
                </div>
              </form>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function AdminPanel() {
  const [users, setUsers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [editData, setEditData] = useState(null);
  const { user } = useAuth();
  
  // Redirect if not admin
  if (user?.role !== 'admin') {
    return (
      <div className="page">
        <div className="access-denied">
          <h2>Access Denied</h2>
          <p>Only administrators can access the Admin Panel.</p>
        </div>
      </div>
    );
  }
  
  useEffect(() => {
    fetchUsers();
  }, []);
  
  const fetchUsers = async () => {
    try {
      const { data } = await api.get('/users');
      setUsers(data.data);
    } catch (error) {
      console.error('Error fetching users:', error);
    } finally {
      setLoading(false);
    }
  };
  
  const handleSubmit = async (e) => {
    e.preventDefault();
    const formData = new FormData(e.target);
    const data = Object.fromEntries(formData.entries());
    
    try {
      if (editData) {
        await api.put(`/users/${editData.id}`, data);
      }
      fetchUsers();
      setShowModal(false);
      setEditData(null);
    } catch (error) {
      alert(error.response?.data?.error || 'An error occurred');
    }
  };
  
  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this user?')) {
      try {
        await api.delete(`/users/${id}`);
        fetchUsers();
      } catch (error) {
        alert(error.response?.data?.error || 'An error occurred');
      }
    }
  };
  
  if (loading) {
    return (
      <div className="loading-screen">
        <div className="spinner-large"></div>
        <p>Loading users...</p>
      </div>
    );
  }
  
  return (
    <div className="admin-panel">
      <header className="page-header">
        <h1>Admin Panel - User Management</h1>
      </header>
      
      <div className="table-container">
        <table className="data-table">
          <thead>
            <tr>
              <th>Username</th>
              <th>Email</th>
              <th>Full Name</th>
              <th>Role</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {users.map((user) => (
              <tr key={user.id}>
                <td>{user.username}</td>
                <td>{user.email}</td>
                <td>{user.full_name || '-'}</td>
                <td>
                  <span className={`role-badge ${user.role}`}>{user.role}</span>
                </td>
                <td className="action-buttons">
                  <button className="btn-icon edit" onClick={() => { setEditData(user); setShowModal(true); }}>
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                      <path d="M11 4H4a2 2 0 00-2 2v14a2 2 0 002 2h14a2 2 0 002-2v-7M18.5 2.5a2.121 2.121 0 013 3L12 15l-4 1 1-4 9.5-9.5z"/>
                    </svg>
                  </button>
                  <button className="btn-icon delete" onClick={() => handleDelete(user.id)}>
                    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                      <path d="M3 6h18M19 6v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/>
                    </svg>
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      
      {showModal && (
        <div className="modal-overlay" onClick={() => setShowModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Edit User</h2>
              <button className="modal-close" onClick={() => setShowModal(false)}>&times;</button>
            </div>
            <form onSubmit={handleSubmit} className="modal-form">
              <div className="form-section">
                <h3>User Information</h3>
                <div className="form-row">
                  <div className="form-group">
                    <label>Username</label>
                    <input name="username" defaultValue={editData?.username} required />
                  </div>
                  <div className="form-group">
                    <label>Email</label>
                    <input type="email" name="email" defaultValue={editData?.email} required />
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group">
                    <label>Full Name</label>
                    <input name="full_name" defaultValue={editData?.full_name || ''} placeholder="Enter full name" />
                  </div>
                  <div className="form-group">
                    <label>Role</label>
                    <select name="role" defaultValue={editData?.role}>
                      <option value="admin">Admin</option>
                      <option value="staff">Staff</option>
                      <option value="manager">Manager</option>
                    </select>
                  </div>
                </div>
              </div>
              <div className="modal-actions">
                <button type="button" className="btn-secondary" onClick={() => setShowModal(false)}>Cancel</button>
                <button type="submit" className="btn-primary">Save Changes</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
